using AiVideoStudio.Domain.Base;using AiVideoStudio.Domain.Enums;using AiVideoStudio.Domain.Events.Operations;
namespace AiVideoStudio.Domain.Entities;
public sealed class SystemNotification:BaseEntity{public string UserId{get;private set;}=string.Empty;public string Title{get;private set;}=string.Empty;public string Message{get;private set;}=string.Empty;public NotificationType Type{get;private set;}public bool IsRead{get;private set;}private SystemNotification(){}public static SystemNotification Create(string user,string title,string message,NotificationType type){if(string.IsNullOrWhiteSpace(user)||string.IsNullOrWhiteSpace(title)||string.IsNullOrWhiteSpace(message))throw new ArgumentException();var n=new SystemNotification{UserId=user,Title=title,Message=message,Type=type,CreatedAt=DateTimeOffset.UtcNow,CreatedBy=user};n.AddDomainEvent(new NotificationCreatedEvent(n.Id,user));return n;}public void MarkRead(){IsRead=true;UpdatedAt=DateTimeOffset.UtcNow;}}
public sealed class UserQuota:BaseEntity{public string UserId{get;private set;}=string.Empty;public QuotaType Type{get;private set;}public long Limit{get;private set;}public long Used{get;private set;}private UserQuota(){}public static UserQuota Create(string user,QuotaType type,long limit)=>new(){UserId=user,Type=type,Limit=limit,CreatedBy=user};public bool Record(long amount){if(amount<0)throw new ArgumentOutOfRangeException(nameof(amount));Used+=amount;UpdatedAt=DateTimeOffset.UtcNow;if(Used>Limit){AddDomainEvent(new QuotaExceededEvent(UserId,Type.ToString()));return false;}return true;}}
public sealed class UsageRecord:BaseEntity{public string UserId{get;private set;}=string.Empty;public QuotaType Type{get;private set;}public long Amount{get;private set;}public string ResourceId{get;private set;}=string.Empty;private UsageRecord(){}public static UsageRecord Create(string user,QuotaType type,long amount,string resource)=>new(){UserId=user,Type=type,Amount=amount,ResourceId=resource,CreatedAt=DateTimeOffset.UtcNow,CreatedBy=user};}
public sealed class SystemConfiguration:BaseEntity{public string Key{get;private set;}=string.Empty;public string Value{get;private set;}=string.Empty;public bool IsSensitive{get;private set;}private SystemConfiguration(){}public static SystemConfiguration Create(string key,string value,bool sensitive=false)=>new(){Key=key,Value=value,IsSensitive=sensitive,CreatedAt=DateTimeOffset.UtcNow,CreatedBy="system"};public void Update(string value,string by){Value=value;UpdatedAt=DateTimeOffset.UtcNow;UpdatedBy=by;}}
public sealed class MaintenanceTask:BaseEntity{public string Name{get;private set;}=string.Empty;public MaintenanceStatus Status{get;private set;}public DateTimeOffset? StartedAt{get;private set;}public DateTimeOffset? CompletedAt{get;private set;}public int DeletedRecords{get;private set;}public string? Error{get;private set;}private MaintenanceTask(){}public static MaintenanceTask Create(string name,string by)=>new(){Name=name,Status=MaintenanceStatus.Pending,CreatedBy=by};public void Start(){Status=MaintenanceStatus.Running;StartedAt=DateTimeOffset.UtcNow;AddDomainEvent(new MaintenanceStartedEvent(Id));}public void Complete(int count){Status=MaintenanceStatus.Completed;DeletedRecords=count;CompletedAt=DateTimeOffset.UtcNow;AddDomainEvent(new MaintenanceCompletedEvent(Id));}public void Fail(string error){Status=MaintenanceStatus.Failed;Error=error;CompletedAt=DateTimeOffset.UtcNow;}}
